-- Competitors: scanned/analyzed agencies offering similar services to DS2.
-- Admin-gated (is_admin()). Seeded with two analyzed examples (Digital Applied,
-- Textura) produced by the first scan run.

create table if not exists public.competitors (
  id          uuid primary key default gen_random_uuid(),
  name        text not null,
  url         text not null,
  summary     text not null default '',
  analysis    jsonb not null default '{}'::jsonb,
  status      text not null default 'pending',  -- pending | analyzing | analyzed | error
  scraped_at  timestamptz,
  created_by  uuid references auth.users (id),
  created_at  timestamptz not null default now(),
  updated_at  timestamptz not null default now()
);
create index if not exists competitors_created_idx on public.competitors (created_at desc);

drop trigger if exists competitors_set_updated_at on public.competitors;
create trigger competitors_set_updated_at before update on public.competitors
  for each row execute function public.set_updated_at();

alter table public.competitors enable row level security;
drop policy if exists competitors_admin_all on public.competitors;
create policy competitors_admin_all on public.competitors
  for all to authenticated using (public.is_admin()) with check (public.is_admin());
grant all on public.competitors to authenticated, service_role;

